                        <h4>反比例函数 y = k/x</h4>
                        <p>k: 比例系数<br>
                        x ≠ 0（定义域限制）<br>
                        图像：双曲线</p>
                    </div>
                    <div class="summary-item">
                        <h4>二次函数 y = ax² + bx + c</h4>
                        <p>a: 开口方向与宽窄<br>
                        顶点: (-b/2a, ...)<br>
                        图像：抛物线</p>
                    </div>
                    <div class="summary-item">
                        <h4>判断函数的方法</h4>
                        <p>给定x，y是否<br>
                        唯一确定？<br>
                        垂直线检验法</p>
                    </div>
                </div>
            </div>
        </div>
    </main>

    <footer>
        <p>🎓 初中数学函数概念交互式学习平台 | 祝学习愉快！</p>
    </footer>

    <script>
        // 全局变量
        let currentTab = 'linear';
        let completedQuestions = new Set();
        let totalQuestions = 6; // 自检清单项目数

        // 初始化
        document.addEventListener('DOMContentLoaded', function() {
            updateLinear();
            updateInverse();
            updateQuadratic();
            updateProgress();
        });

        // 切换标签页
        function switchTab(tabName) {
            // 更新按钮状态
            document.querySelectorAll('.tab-btn').forEach(btn => {
                btn.classList.remove('active');
            });
            event.target.classList.add('active');

            // 显示对应内容
            document.querySelectorAll('.tab-content').forEach(content => {
                content.classList.add('hidden');
            });
            document.getElementById(tabName).classList.remove('hidden');

            currentTab = tabName;
        }

        // 绘制坐标系
        function drawAxes(ctx, width, height) {
            const scale = 40;
            const centerX = width / 2;
            const centerY = height / 2;

            ctx.strokeStyle = '#ddd';
            ctx.lineWidth = 1;

            // 网格线
            for (let i = 0; i <= width; i += scale) {
                ctx.beginPath();
                ctx.moveTo(i, 0);
                ctx.lineTo(i, height);
                ctx.stroke();
            }
            for (let i = 0; i <= height; i += scale) {
                ctx.beginPath();
                ctx.moveTo(0, i);
                ctx.lineTo(width, i);
                ctx.stroke();
            }

            // 坐标轴
            ctx.strokeStyle = '#333';
            ctx.lineWidth = 2;

            // X轴
            ctx.beginPath();
            ctx.moveTo(0, centerY);
            ctx.lineTo(width, centerY);
            ctx.stroke();

            // Y轴
            ctx.beginPath();
            ctx.moveTo(centerX, 0);
            ctx.lineTo(centerX, height);
            ctx.stroke();

            // 箭头和标签
            ctx.fillStyle = '#333';
            ctx.font = '14px Arial';
            ctx.textAlign = 'center';

            // X轴箭头
            ctx.beginPath();
            ctx.moveTo(width - 10, centerY - 5);
            ctx.lineTo(width, centerY);
            ctx.lineTo(width - 10, centerY + 5);
            ctx.fill();
            ctx.fillText('x', width - 20, centerY + 25);

            // Y轴箭头
            ctx.beginPath();
            ctx.moveTo(centerX - 5, 10);
            ctx.lineTo(centerX, 0);
            ctx.lineTo(centerX + 5, 10);
            ctx.fill();
            ctx.fillText('y', centerX + 20, 15);

            // 原点
            ctx.fillText('O', centerX - 15, centerY + 20);

            // 刻度
            ctx.font = '12px Arial';
            for (let i = -5; i <= 5; i++) {
                if (i !== 0) {
                    ctx.fillText(i.toString(), centerX + i * scale, centerY + 20);
                    ctx.fillText((-i).toString(), centerX - 15, centerY + i * scale + 5);
                }
            }
        }

        // 更新一次函数
        function updateLinear() {
            const k = parseFloat(document.getElementById('k1').value);
            const b = parseFloat(document.getElementById('b1').value);

            document.getElementById('k1-val').textContent = `k = ${k}`;
            document.getElementById('b1-val').textContent = `b = ${b}`;
            document.getElementById('linear-formula').textContent = `y = ${k}x ${b >= 0 ? '+' : '-'} ${Math.abs(b)}`;

            const canvas = document.getElementById('linearCanvas');
            const ctx = canvas.getContext('2d');
            const width = canvas.width;
            const height = canvas.height;
            const scale = 40;
            const centerX = width / 2;
            const centerY = height / 2;

            ctx.clearRect(0, 0, width, height);
            drawAxes(ctx, width, height);

            // 绘制函数
            ctx.strokeStyle = '#4a90e2';
            ctx.lineWidth = 3;
            ctx.beginPath();

            const startX = -7;
            const endX = 7;

            for (let x = startX; x <= endX; x += 0.1) {
                const y = k * x + b;
                const canvasX = centerX + x * scale;
                const canvasY = centerY - y * scale;

                if (x === startX) {
                    ctx.moveTo(canvasX, canvasY);
                } else {
                    ctx.lineTo(canvasX, canvasY);
                }
            }
            ctx.stroke();

            // 标注关键点和k、b
            ctx.fillStyle = '#e74c3c';
            ctx.font = 'bold 14px Arial';
            // y轴截距
            ctx.beginPath();
            ctx.arc(centerX, centerY - b * scale, 5, 0, 2 * Math.PI);
            ctx.fill();
            ctx.fillText(`(0, ${b})`, centerX + 10, centerY - b * scale - 10);
        }

        // 更新反比例函数
        function updateInverse() {
            const k = parseFloat(document.getElementById('k2').value);
            if (k === 0) return;

            document.getElementById('k2-val').textContent = `k = ${k}`;
            document.getElementById('inverse-formula').textContent = `y = ${k}/x`;

            const canvas = document.getElementById('inverseCanvas');
            const ctx = canvas.getContext('2d');
            const width = canvas.width;
            const height = canvas.height;
            const scale = 40;
            const centerX = width / 2;
            const centerY = height / 2;

            ctx.clearRect(0, 0, width, height);
            drawAxes(ctx, width, height);

            ctx.strokeStyle = '#f39c12';
            ctx.lineWidth = 3;

            // 绘制渐近线
            ctx.strokeStyle = '#ddd';
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(centerX, 0);
            ctx.lineTo(centerX, height);
            ctx.moveTo(0, centerY);
            ctx.lineTo(width, centerY);
            ctx.stroke();
            ctx.setLineDash([]);

            // 绘制函数（第一象限）
            ctx.strokeStyle = '#f39c12';
            ctx.beginPath();
            let first = true;
            for (let x = 0.1; x <= 7; x += 0.05) {
                const y = k / x;
                if (Math.abs(y) > 7) continue;
                const canvasX = centerX + x * scale;
                const canvasY = centerY - y * scale;
                if (first) {
                    ctx.moveTo(canvasX, canvasY);
                    first = false;
                } else {
                    ctx.lineTo(canvasX, canvasY);
                }
            }
            ctx.stroke();

            // 绘制函数（第三象限）
            ctx.beginPath();
            first = true;
            for (let x = -7; x <= -0.1; x += 0.05) {
                const y = k / x;
                if (Math.abs(y) > 7) continue;
                const canvasX = centerX + x * scale;
                const canvasY = centerY - y * scale;
                if (first) {
                    ctx.moveTo(canvasX, canvasY);
                    first = false;
                } else {
                    ctx.lineTo(canvasX, canvasY);
                }
            }
            ctx.stroke();
        }

        // 更新二次函数
        function updateQuadratic() {
            const a = parseFloat(document.getElementById('a3').value);
            const b = parseFloat(document.getElementById('b3').value);
            const c = parseFloat(document.getElementById('c3').value);

            document.getElementById('a3-val').textContent = `a = ${a}`;
            document.getElementById('b3-val').textContent = `b = ${b}`;
            document.getElementById('c3-val').textContent = `c = ${c}`;

            let formula = `y = ${a}x² `;
            if (b >= 0) formula += `+ ${b}x `;
            else formula += `- ${Math.abs(b)}x `;
            if (c >= 0) formula += `+ ${c}`;
            else formula += `- ${Math.abs(c)}`;
            document.getElementById('quadratic-formula').textContent = formula;

            const canvas = document.getElementById('quadraticCanvas');
            const ctx = canvas.getContext('2d');
            const width = canvas.width;
            const height = canvas.height;
            const scale = 40;
            const centerX = width / 2;
            const centerY = height / 2;

            ctx.clearRect(0, 0, width, height);
            drawAxes(ctx, width, height);

            // 绘制抛物线
            ctx.strokeStyle = '#9b59b6';
            ctx.lineWidth = 3;
            ctx.beginPath();

            const startX = -6;
            const endX = 6;
            let first = true;

            for (let x = startX; x <= endX; x += 0.05) {
                const y = a * x * x + b * x + c;
                if (Math.abs(y) > 7) continue;
                const canvasX = centerX + x * scale;
                const canvasY = centerY - y * scale;

                if (first) {
                    ctx.moveTo(canvasX, canvasY);
                    first = false;
                } else {
                    ctx.lineTo(canvasX, canvasY);
                }
            }
            ctx.stroke();

            // 标注顶点
            if (a !== 0) {
                const vertexX = -b / (2 * a);
                const vertexY = c - b * b / (4 * a);
                if (Math.abs(vertexX) <= 6 && Math.abs(vertexY) <= 6) {
                    ctx.fillStyle = '#e74c3c';
                    ctx.beginPath();
                    ctx.arc(centerX + vertexX * scale, centerY - vertexY * scale, 6, 0, 2 * Math.PI);
                    ctx.fill();
                    ctx.fillStyle = '#333';
                    ctx.font = 'bold 12px Arial';
                    ctx.fillText(`顶点(${vertexX.toFixed(1)}, ${vertexY.toFixed(1)})`, 
                        centerX + vertexX * scale + 15, centerY - vertexY * scale - 10);
                }
            }

            // 标注对称轴
            if (a !== 0) {
                const axisX = -b / (2 * a);
                ctx.strokeStyle = '#e74c3c';
                ctx.setLineDash([5, 5]);
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.moveTo(centerX + axisX * scale, 0);
                ctx.lineTo(centerX + axisX * scale, height);
                ctx.stroke();
                ctx.setLineDash([]);
            }
        }

        // 显示示例
        function showExample(id) {
            alert('点击了示例 ' + id + '！这里可以展开更详细的解释。');
        }

        // 检查答案
        function checkAnswer(element, isCorrect, questionNum) {
            const options = element.parentElement.querySelectorAll('.option');
            options.forEach(opt => {
                opt.style.pointerEvents = 'none';
            });

            if (isCorrect) {
                element.classList.add('correct');
                document.getElementById(`feedback${questionNum}`).textContent = '✅ 正确！';
                document.getElementById(`feedback${questionNum}`).className = 'feedback success show';
                completedQuestions.add(questionNum);
            } else {
                element.classList.add('wrong');
                const correctOption = element.parentElement.querySelector('.option[onclick*="true"]');
                if (correctOption) correctOption.classList.add('correct');
                document.getElementById(`feedback${questionNum}`).textContent = '❌ 错误，正确答案是已标记的选项。';
                document.getElementById(`feedback${questionNum}`).className = 'feedback error show';
            }

            updateProgress();
        }

        // 重置测验
        function resetQuiz() {
            document.querySelectorAll('.option').forEach(opt => {
                opt.classList.remove('correct', 'wrong');
                opt.style.pointerEvents = 'auto';
            });
            document.querySelectorAll('.feedback').forEach(fb => {
                fb.classList.remove('show');
            });
            completedQuestions.clear();
            updateProgress();
        }

        // 切换自检清单
        function toggleCheck(element) {
            element.classList.toggle('checked');
            updateProgress();
        }

        // 更新进度
        function updateProgress() {
            const checklistItems = document.querySelectorAll('.checkbox');
            let checkedCount = 0;
            checklistItems.forEach(item => {
                if (item.classList.contains('checked')) checkedCount++;
            });

            const totalProgress = (completedQuestions.size + checkedCount) / (3 + totalQuestions) * 100;
            document.getElementById('progressBar').style.width = totalProgress + '%';
            document.getElementById('progressText').textContent = `完成度: ${Math.round(totalProgress)}%`;
        }

        // 响应式Canvas
        window.addEventListener('resize', function() {
            updateLinear();
            updateInverse();
            updateQuadratic();
        });
    </script>
</body>
</html>
